import { Component } from '@angular/core';
import { MatDialogRef } from '@angular/material/dialog';
import { MatButtonModule } from '@angular/material/button';
import { MatDialogModule } from '@angular/material/dialog';
import { CommonModule } from '@angular/common';

@Component({
  standalone: true,
  selector: 'app-stale-session-dialog',
  imports: [CommonModule, MatDialogModule, MatButtonModule],
  template: `
  <div class="dialog-container">
    <h2 class="title">Session Conflict</h2>
    <p class="message">
      Another user session is active in this browser. 
      Click OK to sign out the previous session and continue.
    </p>

    <div class="actions">
      <button mat-stroked-button color="primary" (click)="onCancel()">Cancel</button>
      <button mat-flat-button color="warn" (click)="onConfirm()">OK</button>
    </div>
  </div>
`,
  styles: [`
  .dialog-container {
    text-align: center;
    padding: 24px;
    min-width: 300px;
  }
  .title {
    font-size: 20px;
    margin-bottom: 10px;
    color: #d32f2f;
  }
  .message {
    font-size: 16px;
    margin-bottom: 20px;
  }
  .actions {
    display: flex;
    justify-content: center;
    gap: 10px;
  }
`]
})
export class StaleSessionDialogComponent {
  constructor(private dialogRef: MatDialogRef<StaleSessionDialogComponent>) { }

  onConfirm() {
    this.dialogRef.close(true);
  }

  onCancel() {
    this.dialogRef.close(false);
  }
}
